            aOrbiterC = ((aOrbiterC + aOrbiterH) + 0x47DB6383399CEB6DULL) + aPhaseEOrbiterUpdateSaltC[(((31U - aIndex) + 10U)) & 31];
            aOrbiterK = (aOrbiterK ^ aOrbiterC) ^ 0x52DA7B210B28A9B0ULL;
