            //
            aWandererD = aWandererD ^ ((RotL64(aCross, 3U) + RotL64(aOrbiterB, 37U)) + aOrbiterA);
            aWandererC = aWandererC + ((RotL64(aPrevious, 19U) + RotL64(aOrbiterG, 3U)) + aOrbiterC);
            aWandererG = aWandererG ^ ((RotL64(aScatter, 57U) + RotL64(aOrbiterG, 51U)) + aOrbiterB);
