            aOrbiterE = (aOrbiterE + aOrbiterH) + 0x57930323C09164DEULL;
            aOrbiterK = (aOrbiterK ^ aOrbiterE) ^ 0x4869FDA4959B1541ULL;
            aOrbiterK = RotL64((aOrbiterK * 0x0C53F6B345B9B8F1ULL), 37U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterG) + 0xED9B4286E6236DE0ULL;
            aOrbiterA = ((aOrbiterA ^ aOrbiterF) ^ 0xDAE0834D1E237302ULL) ^ aPhaseGOrbiterUpdateSaltC[(((31U - aIndex) + 15U)) & 31];
            aOrbiterA = RotL64((aOrbiterA * 0xDEA1787C44C88E51ULL), 57U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterE) + 0x25ED2EA97E35046BULL;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterI) ^ 0x133E5A53129D1A21ULL;
            aOrbiterJ = RotL64((aOrbiterJ * 0x54BCE5F7EC081203ULL), 19U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterC) + 0xA614659F871F350CULL;
            aOrbiterD = (aOrbiterD ^ aOrbiterG) ^ 0x4F69066C9DE2B96AULL;
            aOrbiterD = RotL64((aOrbiterD * 0x8C2F099E24DB734FULL), 27U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterK) + 0x46D0C3294290EE88ULL;
            aOrbiterF = (aOrbiterF ^ aOrbiterJ) ^ 0x198FD8BC123AE884ULL;
            aOrbiterF = RotL64((aOrbiterF * 0xE63E2C99E1BCC42BULL), 35U);
