            aOrbiterA = (aOrbiterA + aOrbiterD) + 0xD591A985F3685267ULL;
            aOrbiterE = (aOrbiterE ^ aOrbiterA) ^ 0x37DB670A2491E9F5ULL;
            aOrbiterE = RotL64((aOrbiterE * 0x4F9E8704829A6293ULL), 39U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterB) + 0x43307768A695D3D1ULL;
            aOrbiterG = (aOrbiterG ^ aOrbiterK) ^ 0x7936A1DA2EED5BC0ULL;
