            aOrbiterC = ((aOrbiterC ^ aOrbiterB) ^ 0xD197E6751B14D0B9ULL) ^ aPhaseGOrbiterUpdateSaltF[(((31U - aIndex) + 24U)) & 31];
            aOrbiterC = RotL64((aOrbiterC * 0x07BD6943A162698DULL), 3U);
